const html = $input.first().json.data || '';
const url = $input.first().json.query?.url || '';

// Extract job listings from Workday career pages
// Workday uses JSON-LD or specific data attributes
const jobs = [];

// Try to find structured data
const jsonLdMatch = html.match(/<script type="application\/ld\+json">(.*?)<\/script>/gs);
if (jsonLdMatch) {
  for (const match of jsonLdMatch) {
    try {
      const data = JSON.parse(match.replace(/<\/?script[^>]*>/g, ''));
      if (data['@type'] === 'JobPosting') {
        jobs.push({
          title: data.title,
          company: data.hiringOrganization?.name || '',
          location: data.jobLocation?.address?.addressLocality || '',
          description: data.description || '',
          url: data.url || url,
          source: 'workday'
        });
      }
    } catch (e) { /* skip */ }
  }
}

return [{ json: { jobs, source_url: url, count: jobs.length } }];
